## JavaScript Debounce 函数完整实现

```javascript
/**
 * 创建一个防抖函数
 * @param {Function} fn - 需要防抖的函数
 * @param {number} delay - 延迟时间（毫秒）
 * @param {Object} [options] - 配置选项
 * @param {boolean} [options.leading=false] - 是否在延迟开始前立即执行一次
 * @param {boolean} [options.trailing=true] - 是否在延迟结束后执行
 * @param {number} [options.maxWait] - 最大等待时间（保证至少执行一次）
 * @returns {Function} 防抖后的函数
 */
function debounce(fn, delay, options = {}) {
  const {
    leading = false,
    trailing = true,
    maxWait,
  } = options;

  let timerId = null;
  let lastArgs = null;
  let lastThis = null;
  let lastCallTime = 0;    // 上次被调用的时间
  let lastInvokeTime = 0;  // 上次实际执行 fn 的时间
  let maxing = typeof maxWait === 'number' && maxWait > delay;

  // 如果没有 trailing 和 leading，就是个空操作
  if (!leading && !trailing) {
    return () => {};
  }

  // 用 requestAnimationFrame 或 setTimeout
  const useRAF = typeof requestAnimationFrame === 'function';

  function setTimeout(callback, time) {
    if (useRAF && time <= 16) {
      const id = requestAnimationFrame(callback);
      return { type: 'raf', id };
    }
    const id = window.setTimeout(callback, time);
    return { type: 'timeout', id };
  }

  function clearTimer(timer) {
    if (!timer) return;
    if (timer.type === 'raf') {
      cancelAnimationFrame(timer.id);
    } else {
      clearTimeout(timer.id);
    }
  }

  function invokeFn(time) {
    const args = lastArgs;
    const ctx = lastThis;

    lastArgs = null;
    lastThis = null;
    lastInvokeTime = time;

    fn.apply(ctx, args);
  }

  function startTimer(pendingWait, time) {
    // 清除旧定时器
    clearTimer(timerId);

    timerId = setTimeout(() => {
      timerId = null;

      const timeSinceLastCall = Date.now() - lastCallTime;
      const timeSinceLastInvoke = Date.now() - lastInvokeTime;

      // 检查是否该执行 trailing edge
      if (trailing) {
        // 如果 maxing，且距上次执行超过了 maxWait，那已经在 leading 或 maxWait 中执行过了
        if (!maxing || timeSinceLastInvoke < maxWait) {
          invokeFn(time);
        }
      }
    }, pendingWait);
  }

  function debounced(...args) {
    const time = Date.now();
    const isInvoking = shouldInvoke(time);

    lastArgs = args;
    lastThis = this;
    lastCallTime = time;

    if (isInvoking) {
      if (timerId === null) {
        // leading edge 触发
        if (leading) {
          invokeFn(time);
        }
        // trailing edge 也需要时，启动定时器
        if (trailing) {
          startTimer(delay, time);
        }
        return;
      }

      // maxWait 逻辑：保证至少执行一次
      if (maxing) {
        const timeSinceLastInvoke = time - lastInvokeTime;
        const wait = maxWait - timeSinceLastInvoke;

        if (wait <= 0 || wait > delay) {
          // 触发 maxWait，先清掉旧定时器
          clearTimer(timerId);
          timerId = null;
          invokeFn(time);
          if (trailing) {
            startTimer(delay, time);
          }
          return;
        }
      }
    }

    // 常规情况：重新设定定时器
    if (timerId !== null) {
      clearTimer(timerId);
    }
    if (trailing) {
      startTimer(delay, time);
    }
  }

  /**
   * 判断此时是否应该执行 fn
   */
  function shouldInvoke(time) {
    const timeSinceLastCall = time - lastCallTime;
    const timeSinceLastInvoke = time - lastInvokeTime;

    return (
      // 第一次调用时 lastCallTime 为 0
      lastCallTime === 0 ||
      // 距离上次调用已经超过 delay
      timeSinceLastCall >= delay ||
      // 超过了最大等待时间
      (maxing && timeSinceLastInvoke >= maxWait)
    );
  }

  /**
   * 立即执行并取消防抖
   */
  debounced.flush = function () {
    if (timerId === null) return;
    clearTimer(timerId);
    timerId = null;
    if (lastArgs) {
      invokeFn(Date.now());
    }
  };

  /**
   * 取消本次防抖，不执行
   */
  debounced.cancel = function () {
    clearTimer(timerId);
    timerId = null;
    lastArgs = null;
    lastThis = null;
    lastCallTime = 0;
    lastInvokeTime = 0;
  };

  return debounced;
}
```

---

## 最小化版本（面试常用）

```javascript
function debounce(fn, delay, immediate = false) {
  let timer = null;
  return function (...args) {
    const context = this;
    if (timer) clearTimeout(timer);
    if (immediate && !timer) {
      fn.apply(context, args);       // leading 立即执行
    }
    timer = setTimeout(() => {
      if (!immediate) fn.apply(context, args);  // trailing 延迟执行
      timer = null;
    }, delay);
  };
}
```

---

## 使用示例

```javascript
// 1. 搜索框防抖（最经典）
const searchInput = document.getElementById('search');
searchInput.addEventListener('input', debounce(
  (e) => {
    console.log('搜索:', e.target.value);
    // API 请求...
  },
  300
));

// 2. 窗口 resize 防抖
window.addEventListener('resize', debounce(
  () => {
    console.log('窗口尺寸:', window.innerWidth, window.innerHeight);
  },
  200
));

// 3. leading 模式：按钮防连点（立即执行，后续点击防抖）
const saveBtn = document.getElementById('save');
saveBtn.addEventListener('click', debounce(
  () => { console.log('保存中...'); },
  1000,
  { leading: true, trailing: false }
));

// 4. maxWait 保证至少执行一次（如滚动到底部加载）
window.addEventListener('scroll', debounce(
  () => { console.log('加载更多...'); },
  500,
  { leading: true, maxWait: 2000 }
));

// 5. 手动取消/立即刷新
const debouncedLog = debounce((x) => console.log(x), 1000);
debouncedLog('hello');
debouncedLog.cancel();         // 取消，不执行

debouncedLog('world');
debouncedLog.flush();          // 立即执行
```

---

## debounce vs throttle 对比

|                | **Debounce 防抖**                        | **Throttle 节流**                      |
| -------------- | ---------------------------------------- | -------------------------------------- |
| **行为**       | 连续触发时只执行**最后一次**（或第一次） | 连续触发时**定期执行**（每 N ms 一次） |
| **适用场景**   | 搜索联想、resize 完成、自动保存          | 滚动加载、拖拽、FPS 动画               |
| **执行时机**   | 停止触发后 delay ms                      | 固定间隔触发                           |
| **maxWait**    | 可配，避免永远不执行                     | 天然保证                               |

> 📌 **最佳实践**：输入搜索用 debounce（300ms），滚动/拖拽用 throttle（100~200ms），按钮防连点用 leading debounce。

